mapper.select:
SELECT b.book_id, b.book_title, b.author_name, b.publisher, b.publish_date, b.book_price, b.stock_status, b.book_summary, b.cover_image, b.category_id, b.isbn, b.book_stock, b.created_at, b.updated_at, COUNT(r.review_id) AS review_count FROM book b LEFT JOIN review r ON b.book_id = r.book_id
AND (b.book_title LIKE CONCAT('%', #{search}, '%') OR b.author_name LIKE CONCAT('%', #{search}, '%'))
AND b.category_id = #{category_id}
GROUP BY b.book_id
ORDER BY b.created_at DESC ORDER BY b.book_stock DESC ORDER BY review_count DESC ORDER BY b.book_price ASC ORDER BY b.book_price DESC ORDER BY b.book_id DESC
LIMIT #{pageStart}, #{perPageNum}

SELECT COUNT(*) FROM book
AND (book_title LIKE CONCAT('%', #{search}, '%') OR author_name LIKE CONCAT('%', #{search}, '%'))
AND category_id = #{category_id}
